const listsData = $('Trello Lists').item.json || [];
const membersData = $('Trello Members').item.json || [];
const cardsData = $('Trello Cards').item.json || [];

const lists = {};
Object.values(listsData).forEach(l => { if (l.id) lists[l.id] = l.name; });

const members = {};
Object.values(membersData).forEach(m => { if (m.id) members[m.id] = m.fullName; });

const mapEstado = (listName, dueComplete) => {
  if (dueComplete) return 'completada';
  const l = listName.toLowerCase();
  if (l.includes('done') || l.includes('completad')) return 'completada';
  if (l.includes('doing') || l.includes('progress') || l.includes('curso') || l.includes('desarrollo')) return 'en_progreso';
  if (l.includes('review') || l.includes('revisión') || l.includes('seguimiento')) return 'en_revision';
  if (l.includes('blocked') || l.includes('bloquead')) return 'bloqueada';
  return 'pendiente';
};

const MAPPING = {
  "Levantamiento de requerimientos": { nombre: "Project Charter", tipo: "documentacion" },
  "Cronograma": { nombre: "Planificación del Cronograma", tipo: "documentacion" },
  "Diseño de la base de datos": { nombre: "Documentación Técnica Backend", tipo: "tecnico" },
  "Diseño de la arquitectura del sistema": { nombre: "Documentación Técnica Frontend", tipo: "tecnico" },
  "Agenda y Flujo de Atención": { nombre: "Prototipo Funcional Backend", tipo: "prototipo" },
  "Desarrollo del aplicativo móvil": { nombre: "Prototipo Funcional Frontend", tipo: "prototipo" },
  "Pruebas de integración": { nombre: "Pruebas de Integración", tipo: "tecnico" },
  "Desarrollo y entrega de manual de usuario": { nombre: "Manual de Usuario", tipo: "documentacion" }
};

const result = Object.values(cardsData).map(c => {
  const listName = lists[c.idList] || 'Desconocido';
  const memberName = c.idMembers && c.idMembers.length > 0 ? members[c.idMembers[0]] || 'Sin Asignar' : 'Sin Asignar';
  const memberId = c.idMembers && c.idMembers.length > 0 ? c.idMembers[0] : null;

  const mappedDev = MAPPING[c.name];
  const is_deliverable = !!mappedDev;
  const deliverable_name = mappedDev ? mappedDev.nombre : null;
  const deliverable_tipo = mappedDev ? mappedDev.tipo : null;

  const estado = mapEstado(listName, c.dueComplete || (is_deliverable && c.dueComplete));

  const mapDeliverableEstado = (est) => {
    if (est === 'completada') return 'entregado';
    if (est === 'en_revision') return 'en_revision';
    if (est === 'en_progreso') return 'en_progreso';
    return 'pendiente';
  };
  const deliverable_estado = mapDeliverableEstado(estado);

  return {
    card_id: c.id,
    name: c.name,
    desc: c.desc ? c.desc.slice(0, 1000) : '',
    list_name: listName,
    member_id: memberId,
    member_name: memberName,
    start: c.start,
    due: c.due,
    completed: c.dueComplete || estado === 'completada',
    estado: estado,
    attachments_count: c.badges ? c.badges.attachments : 0,
    has_attachments: c.badges ? c.badges.attachments > 0 : false,
    is_deliverable,
    deliverable_name,
    deliverable_tipo,
    deliverable_estado
  };
});

return result.map(r => ({ json: r }));
